// ============================================
// WF-NEW-2: PARSE MESSAGE FROM REDIS - V2
// Converte a string JSON do Redis para objeto
// Lida com diferentes formatos de retorno
// ============================================

const redisData = $input.first().json;

// O Redis pode retornar em diferentes campos dependendo da configuração
// Verificar todas as possibilidades
const payload = redisData.propertyName || redisData.payload || redisData.message || redisData.data || redisData;

// Se veio como string, fazer parse
let message = payload;
if (typeof payload === 'string') {
  try {
    message = JSON.parse(payload);
  } catch (e) {
    return [{
      json: {
        hasMessage: false,
        error: 'Erro ao fazer parse do JSON',
        raw: payload
      }
    }];
  }
}

// Se ainda for null ou undefined
if (!message) {
  return [{
    json: {
      hasMessage: false,
      error: 'Payload vazio',
      raw: redisData
    }
  }];
}

// Verificar se tem os campos essenciais
if (!message.contactPhone) {
  return [{
    json: {
      hasMessage: false,
      error: 'Payload sem contactPhone',
      raw: message
    }
  }];
}

// Retornar mensagem parseada
return [{
  json: {
    hasMessage: true,
    message: message
  }
}];

// ============================================
// WF-NEW-2: PROCESSAR CONTATO - V5
// LÓGICA DE SOURCE_ID:
// 1. Contato existente → usar sourceId do Chatwoot
// 2. Novo contato grupo → usar groupId
// 3. Novo contato individual → usar telefone
// ============================================

// Dados do nó de preparação
const prepData = $('Code - Preparar Contato').first().json;

// A estrutura pode variar
const message = prepData.message || prepData.originalMessage || prepData;

// Resposta do HTTP (pode ser de Buscar ou Criar Contato)
const httpResponse = $input.first().json;

// ============================================
// EXTRAIR INBOX ID DE FORMA SEGURA
// ============================================
const inboxId = message.inboxId 
             || prepData.inboxId 
             || prepData.originalMessage?.inboxId 
             || 5;

// ============================================
// EXTRAIR DADOS DO GRUPO
// ============================================
const isGroup = message.isGroup || prepData.isGroup || false;
const groupId = message.groupId || prepData.groupId || null;

// ============================================
// EXTRAIR CONTACT_ID E SOURCE_ID DA RESPOSTA
// ============================================
let contactId = null;
let sourceIdFromChatwoot = null;
let contactInboxes = [];
let isNewContact = false;

// Verificar formato da resposta
if (httpResponse.payload && Array.isArray(httpResponse.payload)) {
  // CASO 1: Resposta de busca (GET /search) - payload é array
  if (httpResponse.payload.length > 0) {
    const contact = httpResponse.payload[0];
    contactId = contact.id;
    contactInboxes = contact.contact_inboxes || [];
    isNewContact = false;
  } else {
    // Busca não encontrou nada
    isNewContact = true;
  }
} else if (httpResponse.payload?.contact) {
  // CASO 2: Resposta de criação (POST /contacts) - payload.contact
  const contact = httpResponse.payload.contact;
  contactId = contact.id;
  contactInboxes = contact.contact_inboxes || [];
  isNewContact = true;

  // Na criação, também pode vir contact_inbox separado
  if (httpResponse.payload.contact_inbox) {
    sourceIdFromChatwoot = httpResponse.payload.contact_inbox.source_id;
  }
} else if (httpResponse.id) {
  // CASO 3: Resposta direta (id no nível raiz)
  contactId = httpResponse.id;
  contactInboxes = httpResponse.contact_inboxes || [];
  isNewContact = !contactInboxes.length;
}

// ============================================
// BUSCAR SOURCE_ID DO CHATWOOT (se existir)
// ============================================
if (!sourceIdFromChatwoot && contactInboxes.length > 0) {
  // Buscar source_id para o inbox correto
  const inboxMatch = contactInboxes.find(ci => {
    const ciInboxId = ci.inbox?.id || ci.inbox_id;
    return ciInboxId === inboxId;
  });

  if (inboxMatch) {
    sourceIdFromChatwoot = inboxMatch.source_id;
  } else {
    // Se não encontrou para o inbox específico, pegar o primeiro
    sourceIdFromChatwoot = contactInboxes[0]?.source_id || null;
  }
}

// ============================================
// DETERMINAR SOURCE_ID FINAL
// ============================================
let finalSourceId;

if (sourceIdFromChatwoot) {
  // CONTATO EXISTENTE: usar sourceId que já está no Chatwoot
  finalSourceId = sourceIdFromChatwoot;
  console.log('✅ Contato existente - usando sourceId do Chatwoot:', finalSourceId);
} else if (isGroup && groupId) {
  // NOVO CONTATO DE GRUPO: usar groupId
  finalSourceId = groupId.replace('@g.us', '');
  console.log('✅ Novo grupo - usando groupId como sourceId:', finalSourceId);
} else {
  // NOVO CONTATO INDIVIDUAL: usar telefone
  finalSourceId = message.contactPhone || prepData.contactPhone || prepData.identifier;
  console.log('✅ Novo individual - usando telefone como sourceId:', finalSourceId);
}

// ============================================
// LOG PARA DEBUG
// ============================================
console.log('=== PROCESSAR CONTATO V5 ===');
console.log('Contact ID:', contactId);
console.log('Source ID (Chatwoot):', sourceIdFromChatwoot);
console.log('Source ID (Final):', finalSourceId);
console.log('Is New Contact:', isNewContact);
console.log('Is Group:', isGroup);
console.log('Inbox ID:', inboxId);

// ============================================
// VALIDAR CONTACT_ID
// ============================================
if (!contactId) {
  return [{
    json: {
      error: 'Não foi possível extrair contactId',
      httpResponse: httpResponse,
      hasContact: false
    }
  }];
}

// ============================================
// PREPARAR CONTEÚDO DA MENSAGEM
// ============================================
let messageContent = message.content || prepData.content || '';

// Para grupos, adicionar nome do remetente (se ainda não tiver)
const senderName = message.senderName || prepData.senderName || null;
const senderPhone = message.senderPhone || prepData.senderPhone || null;

if (isGroup && senderName && !messageContent.startsWith('*' + senderName)) {
  messageContent = '*' + senderName + '*:\n' + messageContent;
} else if (isGroup && senderPhone && !senderName && !messageContent.startsWith('*')) {
  messageContent = '*' + senderPhone + '*:\n' + messageContent;
}

// Se não tem conteúdo mas tem mídia, usar placeholder
const hasMedia = message.hasMedia || prepData.hasMedia || false;
const messageType = message.messageType || prepData.messageType || 'text';

if (!messageContent && hasMedia) {
  messageContent = '[' + messageType + ']';
}

// ============================================
// RETORNAR DADOS PROCESSADOS
// ============================================
return [{
  json: {
    // Contato
    contactId: contactId,
    sourceId: finalSourceId,
    hasContact: true,
    isNewContact: isNewContact,

    // Inbox
    inboxId: inboxId,

    // Mensagem
    content: messageContent,
    messageType: messageType,

    // Mídia
    hasMedia: hasMedia,
    mediaUrl: message.mediaUrl || prepData.mediaUrl || null,
    mimeType: message.mimeType || prepData.mimeType || null,
    fileName: message.fileName || prepData.fileName || null,

    // Contexto
    isGroup: isGroup,
    groupId: groupId,
    senderName: senderName,
    senderPhone: senderPhone,
    identifier: prepData.identifier,

    // Mensagem original
    originalMessage: message
  }
}];

// ============================================
// WF-NEW-2: PROCESSAR CONVERSA - V3 COM FILTRO INBOX
// Extrai conversation_id SOMENTE do inbox correto
// ============================================

// Dados do nó anterior (Processar Contato)
const prepData = $('Code - Processar Contato').first().json;
const targetInboxId = prepData.inboxId;

// Resposta do HTTP (pode ser de Buscar ou Criar Conversa)
const httpResponse = $input.first().json;

// Extrair conversation_id
let conversationId = null;
let needsNewConversation = false;

// Log para debug
console.log('=== PROCESSAR CONVERSA V3 ===');
console.log('Target Inbox ID:', targetInboxId);

// A resposta pode vir em diferentes formatos
// 1. Busca conversas: { payload: [{ id, status, inbox_id, ... }] }
// 2. Criação: { id, inbox_id, ... }

if (httpResponse.payload && Array.isArray(httpResponse.payload)) {
  // Resposta de busca - FILTRAR PELO INBOX CORRETO
  console.log('Total de conversas encontradas:', httpResponse.payload.length);

  // Filtrar conversas pelo inbox correto
  const conversasDoInbox = httpResponse.payload.filter(c => c.inbox_id === targetInboxId);
  console.log('Conversas no inbox', targetInboxId + ':', conversasDoInbox.length);

  if (conversasDoInbox.length > 0) {
    // Preferir conversa aberta
    const openConv = conversasDoInbox.find(c => c.status === 'open');
    if (openConv) {
      conversationId = openConv.id;
      console.log('Usando conversa aberta:', conversationId);
    } else {
      // Pegar a mais recente (primeira)
      conversationId = conversasDoInbox[0].id;
      console.log('Usando conversa mais recente:', conversationId);
    }
  } else {
    // Não encontrou conversa no inbox correto - precisa criar
    console.log('❌ Nenhuma conversa no inbox', targetInboxId, '- precisa criar nova');
    needsNewConversation = true;
  }

} else if (httpResponse.id) {
  // Resposta de criação - usar diretamente
  conversationId = httpResponse.id;
  console.log('Conversa criada:', conversationId);
}

// Se não encontrou conversa no inbox correto, sinalizar para criar
if (needsNewConversation || !conversationId) {
  return [{
    json: {
      hasConversation: false,
      needsNewConversation: true,

      // Passar dados para criar conversa
      contactId: prepData.contactId,
      sourceId: prepData.sourceId,
      inboxId: targetInboxId,

      // Dados da mensagem
      content: prepData.content,
      messageType: prepData.messageType,
      hasMedia: prepData.hasMedia,
      mediaUrl: prepData.mediaUrl,
      mimeType: prepData.mimeType,
      fileName: prepData.fileName,
      isGroup: prepData.isGroup,

      // Debug
      originalMessage: prepData.originalMessage,
      httpResponse: httpResponse
    }
  }];
}

return [{
  json: {
    // Conversa
    conversationId: conversationId,
    hasConversation: true,
    needsNewConversation: false,

    // Dados para criar mensagem
    content: prepData.content,
    messageType: prepData.messageType,

    // Mídia
    hasMedia: prepData.hasMedia,
    mediaUrl: prepData.mediaUrl,
    mimeType: prepData.mimeType,
    fileName: prepData.fileName,

    // Contato
    contactId: prepData.contactId,
    sourceId: prepData.sourceId,
    inboxId: targetInboxId,

    // Contexto
    isGroup: prepData.isGroup,

    // Debug
    originalMessage: prepData.originalMessage
  }
}];

// ============================================
// WF-NEW-2: PREPARAR CONTATO - V5 COM FORMATAÇÃO MÍDIA
// Adaptado para UAZAPI
// ============================================
// LÓGICA CORRETA:
// - GRUPO: identifier = groupId (@g.us), SEM phone_number
// - INDIVIDUAL: identifier = telefone, COM phone_number
// ============================================

const input = $input.first().json;
const message = input.message || input;

// ============================================
// FUNÇÃO: Formatar Tipo de Mídia com Emoji
// ============================================
function formatMediaType(messageType, mimeType) {
  // Verificar por mimeType primeiro (mais específico)
  if (mimeType) {
    if (mimeType === 'application/pdf') return '📄 *PDF*';
    if (mimeType.startsWith('image/')) return '🖼️ *Imagem*';
    if (mimeType.startsWith('audio/')) return '🎵 *Áudio*';
    if (mimeType.startsWith('video/')) return '🎬 *Vídeo*';
    if (mimeType.includes('document') || mimeType.includes('sheet') || mimeType.includes('word')) {
      return '📄 *Documento*';
    }
    if (mimeType.includes('zip') || mimeType.includes('rar') || mimeType.includes('compressed')) {
      return '🗃️ *Arquivo Compactado*';
    }
  }

  // Fallback por messageType
  const mediaFormats = {
    'document': '📄 *Documento*',
    'image': '🖼️ *Imagem*',
    'audio': '🎵 *Áudio*',
    'ptt': '🎤 *Áudio*',
    'voice': '🎤 *Áudio*',
    'video': '🎬 *Vídeo*',
    'sticker': '🎭 *Figurinha*',
    'location': '📍 *Localização*',
    'contact': '👤 *Contato*',
    'gif': '🎞️ *GIF*'
  };

  return mediaFormats[messageType] || '📎 *Arquivo*';
}

// ============================================
// EXTRAIR DADOS DA MENSAGEM (formato UAZAPI)
// ============================================
const isGroup = message.isGroup || false;
const contactPhone = message.contactPhone || '';
const contactName = message.contactName || '';
const senderPhone = message.senderPhone || '';
const senderName = message.senderName || '';
const groupId = message.groupId || null;
const groupName = message.groupName || '';
const avatarUrl = message.avatarUrl || null;
const inboxId = message.inboxId || 5;

// ============================================
// DEFINIR IDENTIFICADORES - LÓGICA CORRETA
// ============================================
let identifier;
let sourceId;
let phoneNumber;
let nameForContact;

if (isGroup && groupId) {
  // ============================================
  // GRUPO: O GRUPO É O CONTATO
  // ============================================

  // identifier = ID completo do grupo (com @g.us)
  identifier = groupId;

  // sourceId = ID do grupo sem @g.us
  sourceId = groupId.replace('@g.us', '');

  // IMPORTANTE: Grupos NÃO têm telefone!
  phoneNumber = null;

  // Nome do contato = nome do grupo
  nameForContact = groupName || contactName || 'Grupo ' + sourceId;

  console.log('✅ GRUPO detectado');
  console.log('   identifier:', identifier);
  console.log('   sourceId:', sourceId);
  console.log('   nome:', nameForContact);

} else {
  // ============================================
  // INDIVIDUAL: A PESSOA É O CONTATO
  // ============================================

  // identifier = telefone
  identifier = contactPhone;

  // sourceId = telefone
  sourceId = contactPhone;

  // Telefone com formato internacional
  phoneNumber = contactPhone ? 
    (contactPhone.startsWith('+') ? contactPhone : '+' + contactPhone) : null;

  // Nome do contato = nome da pessoa
  nameForContact = contactName || senderName || contactPhone;

  console.log('✅ INDIVIDUAL detectado');
  console.log('   identifier:', identifier);
  console.log('   sourceId:', sourceId);
}

// ============================================
// PREPARAR CONTEÚDO DA MENSAGEM
// ============================================
let content = message.content || '';
const hasMedia = message.hasMedia || false;
const messageType = message.messageType || 'text';
const mimeType = message.mimeType || null;

// Se tem mídia, formatar o tipo com emoji
let mediaLabel = '';
if (hasMedia && messageType !== 'text') {
  mediaLabel = formatMediaType(messageType, mimeType);
}

// Para grupos, adicionar nome do remetente NO CORPO DA MENSAGEM
if (isGroup && senderName) {
  if (content && !content.startsWith('*' + senderName)) {
    // Tem conteúdo texto
    if (hasMedia && mediaLabel) {
      // Mídia com caption
      content = '*' + senderName + '*:\n' + mediaLabel + '\n' + content;
    } else {
      // Só texto
      content = '*' + senderName + '*:\n' + content;
    }
  } else if (!content && hasMedia) {
    // Só mídia, sem texto
    content = '*' + senderName + '*:\n' + mediaLabel;
  }
} else if (isGroup && senderPhone && !senderName) {
  // Grupo sem nome do remetente, usar telefone
  if (content && !content.startsWith('*')) {
    if (hasMedia && mediaLabel) {
      content = '*' + senderPhone + '*:\n' + mediaLabel + '\n' + content;
    } else {
      content = '*' + senderPhone + '*:\n' + content;
    }
  } else if (!content && hasMedia) {
    content = '*' + senderPhone + '*:\n' + mediaLabel;
  }
} else if (!isGroup && hasMedia && !content) {
  // Individual, só mídia sem texto
  content = mediaLabel;
} else if (!isGroup && hasMedia && content) {
  // Individual, mídia com caption
  content = mediaLabel + '\n' + content;
}

// ============================================
// RETORNAR DADOS PREPARADOS
// ============================================
return [{
  json: {
    // Identificadores CORRETOS
    identifier: identifier,
    sourceId: sourceId,

    // Dados do contato
    contactName: nameForContact,
    phoneNumber: phoneNumber,  // NULL para grupos!
    avatarUrl: avatarUrl,

    // Inbox
    inboxId: inboxId,

    // Contexto de grupo
    isGroup: isGroup,
    groupId: groupId,
    groupName: groupName,

    // Remetente (para mensagem)
    senderPhone: senderPhone,
    senderName: senderName,

    // Mensagem
    content: content,
    messageType: messageType,

    // Mídia
    hasMedia: hasMedia,
    mediaUrl: message.mediaUrl || null,
    mimeType: mimeType,
    fileName: message.fileName || null,

    // Original
    originalMessage: message
  }
}];

// ============================================
// WF-NEW-2: VERIFICAR INBOX - V2
// Corrigido para buscar dados corretamente
// ============================================

const input = $input.first().json;

// ============================================
// BUSCAR DADOS DA MENSAGEM ORIGINAL
// ============================================
// Tentar buscar de múltiplos nós possíveis
let dadosMensagem = null;

const possibleNodes = [
  'Code - Processar Conversa',
  'Code - Preparar Conversa',
  'IF - Tem Conversa?',
  'Code - Processar Contato',
  'Code - Preparar Contato'
];

for (const nodeName of possibleNodes) {
  try {
    const nodeData = $(nodeName).first();
    if (nodeData && nodeData.json) {
      // Verificar se tem os dados que precisamos
      if (nodeData.json.originalMessage || nodeData.json.hasMedia !== undefined) {
        dadosMensagem = nodeData.json;
        console.log('✅ Dados encontrados no nó:', nodeName);
        break;
      }
    }
  } catch (e) {
    // Nó não existe, continuar
  }
}

// Se não encontrou, tentar usar o input direto
if (!dadosMensagem) {
  dadosMensagem = input;
  console.log('⚠️ Usando input direto');
}

// ============================================
// EXTRAIR DADOS DO CONTATO/CONVERSA
// ============================================
// Dados podem vir do input (resposta HTTP) ou de dadosMensagem
const dadosContato = input.meta?.sender || input.sender || {};

// ID do contato - pode vir de várias fontes
const contactId = dadosMensagem.contactId 
                || dadosContato.id 
                || input.contact_id 
                || null;

// ID da conversa - pode vir do input (resposta da criação)
const conversationId = input.id || dadosMensagem.conversationId || null;

// Source ID
const sourceId = dadosMensagem.sourceId 
              || input.source_id 
              || null;

// Inbox ID
const inboxId = dadosMensagem.inboxId 
             || input.inbox_id 
             || dadosMensagem.originalMessage?.inboxId 
             || 5;

// ============================================
// EXTRAIR DADOS DA MENSAGEM - PRIORIDADE CORRETA
// ============================================
// 1. Primeiro tentar de dadosMensagem diretamente
// 2. Depois de originalMessage
// 3. Por último defaults

const originalMsg = dadosMensagem.originalMessage || {};

// Conteúdo
const content = dadosMensagem.content 
             || originalMsg.content 
             || '';

// Tipo de mensagem
const messageType = dadosMensagem.messageType 
                 || originalMsg.messageType 
                 || 'text';

// Mídia
const hasMedia = dadosMensagem.hasMedia 
              || originalMsg.hasMedia 
              || false;

const mediaUrl = dadosMensagem.mediaUrl 
              || originalMsg.mediaUrl 
              || null;

const mimeType = dadosMensagem.mimeType 
              || originalMsg.mimeType 
              || null;

const fileName = dadosMensagem.fileName 
              || originalMsg.fileName 
              || null;

// Grupo
const isGroup = dadosMensagem.isGroup 
             || originalMsg.isGroup 
             || false;

// Nome do remetente
const senderName = dadosMensagem.senderName 
                || originalMsg.senderName 
                || dadosMensagem.originalMessage?.senderName
                || null;

// ============================================
// VERIFICAR SE TEM CONVERSA NO INBOX CORRETO
// ============================================
const targetInbox = dadosMensagem.targetInbox || inboxId;

// Verificar se a conversa existe e está no inbox correto
const hasConversationInbox = !!conversationId && (input.inbox_id === targetInbox || !input.inbox_id);

// ============================================
// LOG DE DEBUG
// ============================================
console.log('=== DEBUG VERIFICAR INBOX ===');
console.log('hasMedia:', hasMedia);
console.log('mediaUrl:', mediaUrl ? 'SIM' : 'NÃO');
console.log('messageType:', messageType);
console.log('content:', content ? content.substring(0, 50) + '...' : '(vazio)');
console.log('conversationId:', conversationId);
console.log('contactId:', contactId);

// ============================================
// RETORNAR DADOS CONSOLIDADOS
// ============================================
return [{
  json: {
    // Status da conversa
    hasConversationInbox: hasConversationInbox,
    conversationId: conversationId,

    // IDs
    inboxId: inboxId,
    contactId: contactId,
    sourceId: sourceId,

    // Mensagem - DADOS PRESERVADOS
    content: content,
    messageType: messageType,

    // Mídia - DADOS PRESERVADOS
    hasMedia: hasMedia,
    mediaUrl: mediaUrl,
    mimeType: mimeType,
    fileName: fileName,

    // Grupo
    isGroup: isGroup,
    senderName: senderName,

    // Inbox alvo
    targetInbox: targetInbox,

    // Dados originais para referência
    originalMessage: dadosMensagem.originalMessage || originalMsg
  }
}];

// ============================================
// WF-NEW-2: PROCESSAR DOWNLOAD - V6
// Com tratamento de erros de download CORRIGIDO
// ============================================

const input = $input.first().json;

// ============================================
// BUSCAR DADOS ANTERIORES
// ============================================

let prevData = null;
const possibleNodes = [
  'Code - Preparar Download Midia',
  'Code - Preparar Download Mídia',
  'IF - Tem Mídia?',
  'IF - Tem Media?',
  'Code - Processar Conversa'
];

for (const nodeName of possibleNodes) {
  try {
    const data = $(nodeName).first();
    if (data && data.json) {
      prevData = data.json;
      break;
    }
  } catch (e) {
    continue;
  }
}

if (!prevData) {
  prevData = {};
}

// ============================================
// VERIFICAR SE HOUVE ERRO NO DOWNLOAD
// ============================================

// Quando "Continue On Fail" está ativo, erro vem em input.error
const hasError = !!input.error;

// Extrair mensagem de erro (pode ser objeto ou string)
let errorMessage = '';
if (input.error) {
  if (typeof input.error === 'string') {
    errorMessage = input.error;
  } else if (input.error.message) {
    errorMessage = String(input.error.message);
  } else {
    errorMessage = JSON.stringify(input.error);
  }
}

// Também verificar outros campos de erro
if (!errorMessage && input.errorMessage) {
  errorMessage = String(input.errorMessage);
}
if (!errorMessage && input.errorDescription) {
  errorMessage = String(input.errorDescription);
}

// Erros comuns do UAZAPI
const knownErrors = [
  'hash of media ciphertext',
  'no url present',
  'media not found',
  'file not found',
  'expired',
  'timeout',
  'failed to download'
];

// Verificar se é erro conhecido
const errorLower = errorMessage.toLowerCase();
const isKnownError = knownErrors.some(err => errorLower.includes(err.toLowerCase()));

// ============================================
// SE HOUVE ERRO - FALLBACK PARA TEXTO
// ============================================

if (hasError || isKnownError) {
  console.log('⚠️ Erro no download de mídia:', errorMessage);

  // Preparar mensagem de fallback
  let fallbackContent = prevData.content || '';

  // Tipo de mídia
  const mediaType = prevData.messageType 
    || prevData.originalMessage?.messageType 
    || 'mídia';

  // Adicionar aviso sobre mídia não disponível
  if (fallbackContent && fallbackContent.trim()) {
    fallbackContent = fallbackContent + '\n\n[' + mediaType + ' não disponível]';
  } else {
    fallbackContent = '[' + mediaType + ' não disponível]';
  }

  return [{
    json: {
      downloadSuccess: false,
      downloadError: errorMessage || 'Erro desconhecido no download',

      // Fallback para envio como texto
      sendAsText: true,

      // Dados da conversa
      conversationId: prevData.conversationId,
      hasConversation: prevData.hasConversation,

      // Mensagem (sem mídia)
      content: fallbackContent,
      messageType: 'text',
      hasMedia: false,

      // Outros dados
      contactId: prevData.contactId,
      sourceId: prevData.sourceId,
      inboxId: prevData.inboxId,
      isGroup: prevData.isGroup
    }
  }];
}

// ============================================
// DOWNLOAD OK - EXTRAIR URL DO ARQUIVO
// ============================================

// A resposta do UAZAPI vem com fileURL
const fileUrl = input.fileURL || input.fileUrl || input.url || input.link || null;

if (!fileUrl) {
  console.log('⚠️ Download retornou sem URL do arquivo');
  console.log('Input recebido:', JSON.stringify(input));

  // Preparar fallback
  let fallbackContent = prevData.content || '';
  const mediaType = prevData.messageType || 'mídia';

  if (fallbackContent && fallbackContent.trim()) {
    fallbackContent = fallbackContent + '\n\n[' + mediaType + ' não disponível]';
  } else {
    fallbackContent = '[' + mediaType + ' não disponível]';
  }

  return [{
    json: {
      downloadSuccess: false,
      downloadError: 'Resposta sem URL do arquivo',
      sendAsText: true,
      conversationId: prevData.conversationId,
      hasConversation: prevData.hasConversation,
      content: fallbackContent,
      messageType: 'text',
      hasMedia: false,
      contactId: prevData.contactId,
      sourceId: prevData.sourceId,
      inboxId: prevData.inboxId,
      isGroup: prevData.isGroup
    }
  }];
}

// ============================================
// SUCESSO - RETORNAR URL PARA BAIXAR
// ============================================

return [{
  json: {
    downloadSuccess: true,

    // URL do arquivo para baixar
    fileUrl: fileUrl,

    // Dados da mídia
    mimeType: input.mimetype || input.mimeType || prevData.mimeType,
    fileName: input.filename || input.fileName || prevData.fileName,

    // Dados da conversa
    conversationId: prevData.conversationId,
    hasConversation: prevData.hasConversation,

    // Conteúdo (caption)
    content: prevData.content,
    messageType: prevData.messageType,

    // Outros dados
    contactId: prevData.contactId,
    sourceId: prevData.sourceId,
    inboxId: prevData.inboxId,
    isGroup: prevData.isGroup
  }
}];

// ============================================
// WF-NEW-2: PREPARAR DOWNLOAD MÍDIA - V2
// Com validação de URL disponível
// ============================================

const prevData = $input.first().json;
const message = prevData.originalMessage || prevData;

// ============================================
// VALIDAR SE TEM URL PARA BAIXAR
// ============================================

// Para UAZAPI: precisa da URL do WhatsApp
// Para 360Dialog: precisa do media_id

const platform = message.platform || 'uazapi';
const hasMediaUrl = !!message.mediaUrl;

// Se não tem URL/ID de mídia, não pode baixar
if (!hasMediaUrl) {
  return [{
    json: {
      // Marcar que não pode baixar
      canDownload: false,
      downloadError: 'Mídia sem URL disponível - possivelmente expirada',

      // Passar dados da conversa
      conversationId: prevData.conversationId,
      hasConversation: prevData.hasConversation,

      // Fallback: enviar como texto
      content: prevData.content || '[Mídia não disponível]',
      messageType: 'text',
      hasMedia: false,

      // Manter outros dados
      contactId: prevData.contactId,
      sourceId: prevData.sourceId,
      inboxId: prevData.inboxId,
      isGroup: prevData.isGroup,

      // Mensagem original para referência
      originalMessage: message
    }
  }];
}

// ============================================
// PREPARAR DOWNLOAD - UAZAPI
// ============================================

if (platform === 'uazapi') {
  // Extrair messageId (remover prefixo owner se tiver)
  let messageId = message.messageId || '';
  if (messageId.includes(':')) {
    messageId = messageId.split(':')[1];
  }

  // Determinar token baseado no owner
  const TOKENS = {
    '556192894339': '6220a163-28da-40dc-ae09-cc2bdbe695f6',  // EEG
    '556183008973': '88950a6f-0824-4c1d-a4b6-023f4c66cb28'   // Recepção
  };

  const owner = message.owner || '';
  const token = TOKENS[owner] || '';

  if (!token) {
    return [{
      json: {
        canDownload: false,
        downloadError: `Token não encontrado para owner: ${owner}`,
        conversationId: prevData.conversationId,
        hasConversation: prevData.hasConversation,
        content: prevData.content || '[Erro ao baixar mídia]',
        messageType: 'text',
        hasMedia: false,
        contactId: prevData.contactId,
        sourceId: prevData.sourceId,
        inboxId: prevData.inboxId,
        isGroup: prevData.isGroup,
        originalMessage: message
      }
    }];
  }

  // Determinar se precisa converter para MP3 (áudio)
  const isAudio = message.messageType === 'audio' 
               || message.messageType === 'ptt' 
               || message.messageType === 'voice'
               || message.mimeType?.startsWith('audio/');

  return [{
    json: {
      canDownload: true,

      // Config para download UAZAPI
      downloadConfig: {
        messageId: messageId,
        token: token,
        owner: owner,
        generateMp3: isAudio,
        returnLink: true,
        returnBase64: false
      },

      // Dados da conversa
      conversationId: prevData.conversationId,
      hasConversation: prevData.hasConversation,

      // Dados da mensagem
      content: prevData.content,
      messageType: message.messageType,
      hasMedia: true,
      mimeType: message.mimeType,
      fileName: message.fileName,

      // Outros dados
      contactId: prevData.contactId,
      sourceId: prevData.sourceId,
      inboxId: prevData.inboxId,
      isGroup: prevData.isGroup,

      // Mensagem original
      originalMessage: message
    }
  }];
}

// ============================================
// PREPARAR DOWNLOAD - 360DIALOG
// ============================================

if (platform === '360dialog') {
  // Para 360Dialog, o mediaUrl é o media_id
  const mediaId = message.mediaUrl;

  return [{
    json: {
      canDownload: true,

      // Config para download 360Dialog
      downloadConfig: {
        mediaId: mediaId,
        platform: '360dialog'
      },

      // Dados da conversa
      conversationId: prevData.conversationId,
      hasConversation: prevData.hasConversation,

      // Dados da mensagem
      content: prevData.content,
      messageType: message.messageType,
      hasMedia: true,
      mimeType: message.mimeType,
      fileName: message.fileName,

      // Outros dados
      contactId: prevData.contactId,
      sourceId: prevData.sourceId,
      inboxId: prevData.inboxId,
      isGroup: prevData.isGroup,

      // Mensagem original
      originalMessage: message
    }
  }];
}

// ============================================
// PLATAFORMA NÃO SUPORTADA
// ============================================

return [{
  json: {
    canDownload: false,
    downloadError: `Plataforma não suportada para download: ${platform}`,
    conversationId: prevData.conversationId,
    hasConversation: prevData.hasConversation,
    content: prevData.content || '[Mídia não disponível]',
    messageType: 'text',
    hasMedia: false,
    contactId: prevData.contactId,
    sourceId: prevData.sourceId,
    inboxId: prevData.inboxId,
    isGroup: prevData.isGroup,
    originalMessage: message
  }
}];

// ============================================
// WF-NEW-2: PROCESSAR URL MÍDIA 360DIALOG
// Extrai a URL real da resposta do 360Dialog
// e prepara para download
// ============================================

const prevData = $input.first().json;

// A resposta do primeiro GET contém a URL do Facebook CDN
// Precisamos substituir o host para usar via 360Dialog
const response = prevData;

// Verificar erro
if (response.error) {
  return [{
    json: {
      downloadSuccess: false,
      downloadError: response.error,
      sendAsText: true,
      conversationId: prevData.conversationId,
      content: prevData.content || '[Erro ao obter URL da mídia]'
    }
  }];
}

// A URL vem no campo "url" e começa com https://lookaside.fbsbx.com
const facebookUrl = response.url;

if (!facebookUrl) {
  return [{
    json: {
      downloadSuccess: false,
      downloadError: 'URL não retornada pelo 360Dialog',
      sendAsText: true,
      conversationId: prevData.conversationId,
      content: prevData.content || '[Mídia não disponível]'
    }
  }];
}

// Substituir o host do Facebook pelo 360Dialog
// De: https://lookaside.fbsbx.com/whatsapp_business/attachments/?mid=...
// Para: https://waba-v2.360dialog.io/whatsapp_business/attachments/?mid=...

let downloadUrl = facebookUrl;
if (facebookUrl.includes('lookaside.fbsbx.com')) {
  downloadUrl = facebookUrl.replace('https://lookaside.fbsbx.com', 'https://waba-v2.360dialog.io');
}

// Se a URL usa escape de barra, corrigir
downloadUrl = downloadUrl.replace(/\\\//g, '/');

return [{
  json: {
    // URL para download
    downloadUrl: downloadUrl,

    // Dados da mídia
    mimeType: response.mime_type || prevData.mimeType,
    fileSize: response.file_size || null,

    // Passar dados da conversa
    conversationId: prevData.conversationId,
    content: prevData.content,
    fileName: prevData.fileName,
    messageType: prevData.messageType,
    contactId: prevData.contactId,
    inboxId: prevData.inboxId,
    isGroup: prevData.isGroup
  }
}];

// ============================================
// WF-02: VERIFICAR E PREPARAR BUSCA DE MENÇÕES
// Colocar APÓS "Code - Parse Message"
// ============================================

const input = $input.first().json;

// Verificar se tem mensagem válida
if (!input.hasMessage || !input.message) {
  return [{
    json: {
      ...input,
      hasMentions: false
    }
  }];
}

const message = input.message;

// ============================================
// VERIFICAR SE TEM MENÇÕES (UAZAPI)
// ============================================

// As menções vêm em message.content.contextInfo.mentionedJID
// ou podem estar em outros lugares dependendo do formato

let mentionedJIDs = [];

// Tentar extrair de diferentes locais
if (message.content?.contextInfo?.mentionedJID) {
  mentionedJIDs = message.content.contextInfo.mentionedJID;
} else if (message.mentionedJID) {
  mentionedJIDs = message.mentionedJID;
} else if (message.contextInfo?.mentionedJID) {
  mentionedJIDs = message.contextInfo.mentionedJID;
}

// Se não tem menções, passar adiante
if (!mentionedJIDs || mentionedJIDs.length === 0) {
  return [{
    json: {
      ...input,
      hasMentions: false
    }
  }];
}

// ============================================
// TEM MENÇÕES - PREPARAR LISTA PARA BUSCA
// ============================================

console.log('🔍 Menções detectadas:', mentionedJIDs.length);

return [{
  json: {
    ...input,
    hasMentions: true,
    mentionedJIDs: mentionedJIDs,
    originalContent: message.content || ''
  }
}];

// ============================================
// WF-02: RESOLVER MENÇÕES
// Colocar APÓS "PostgreSQL - Buscar Nomes"
// ============================================

// Dados anteriores (do nó IF - Tem Menções? ou Code - Verificar Menções)
let prevData;
try {
  prevData = $('Code - Verificar Menções').first().json;
} catch (e) {
  prevData = $('IF - Tem Menções?').first().json;
}

// Se não conseguiu pegar dados anteriores, tentar de outra forma
if (!prevData || !prevData.message) {
  prevData = $input.first().json;
}

// Resultado da busca no PostgreSQL
const cacheResults = $input.all().map(item => item.json);

// ============================================
// CRIAR MAPA LID -> NOME
// ============================================

const nameMap = {};

for (const row of cacheResults) {
  if (row.lid && row.push_name) {
    // Mapear LID completo
    nameMap[row.lid] = row.push_name;

    // Também mapear só o número (sem @lid)
    const lidNumber = row.lid.replace('@lid', '');
    nameMap[lidNumber] = row.push_name;
  }
}

console.log('📝 Cache de nomes encontrado:', Object.keys(nameMap).length, 'registros');

// ============================================
// SUBSTITUIR MENÇÕES NO TEXTO
// ============================================

const message = prevData.message || {};
let originalText = '';

// Tentar extrair texto de diferentes locais
if (typeof message.content === 'string') {
  originalText = message.content;
} else if (message.content?.text) {
  originalText = message.content.text;
} else if (message.text) {
  originalText = message.text;
}

let resolvedText = originalText;
let replacementsCount = 0;

for (const mentionJID of (prevData.mentionedJIDs || [])) {
  // Extrair número do LID
  const lidNumber = mentionJID.replace('@lid', '').replace('@s.whatsapp.net', '');

  // Buscar nome no mapa
  const name = nameMap[mentionJID] || nameMap[lidNumber];

  if (name) {
    // Substituir @número por @Nome
    const regex = new RegExp(`@${lidNumber}`, 'g');
    resolvedText = resolvedText.replace(regex, `@${name}`);
    replacementsCount++;
    console.log(`✅ Substituído: @${lidNumber} -> @${name}`);
  } else {
    console.log(`⚠️ Nome não encontrado para: ${lidNumber}`);
  }
}

// ============================================
// ATUALIZAR MENSAGEM COM TEXTO RESOLVIDO
// ============================================

const updatedMessage = { ...message };

// Atualizar o texto em todos os lugares possíveis
if (typeof updatedMessage.content === 'string') {
  updatedMessage.content = resolvedText;
} else if (updatedMessage.content?.text) {
  updatedMessage.content.text = resolvedText;
}
if (updatedMessage.text) {
  updatedMessage.text = resolvedText;
}

// ============================================
// RETORNAR DADOS ATUALIZADOS
// ============================================

console.log(`✅ Menções resolvidas: ${replacementsCount} de ${(prevData.mentionedJIDs || []).length}`);

return [{
  json: {
    hasMessage: true,
    message: updatedMessage,
    mentionsResolved: true,
    replacementsCount: replacementsCount
  }
}];
